import ast

class SyntaxValidator(Tool):
    name = 'validate_syntax'
    description = 'Check Python code syntax validity'

    def execute(self, code: str) -> dict:
        try:
            ast.parse(code)
            return {'valid': True, 'errors': []}
        except SyntaxError as e:
            return {'valid': False, 'errors': [str(e)]}

class SafetyScanner(Tool):
    name = 'scan_safety'
    DANGEROUS = ['exec(', 'eval(', 'open(', 'import os', '__import__']

    def execute(self, code: str) -> dict:
        issues = [pat for pat in self.DANGEROUS if pat in code]
        return {'safe': len(issues) == 0, 'issues': issues}

