from vex_sdk import VexClient

vex = VexClient(api_key='your-vex-key')

@vex.policy('code-generation-high-risk')
def verify_code_safety(event):
    if event.type == 'tool_call' and event.tool == 'sandbox_exec':
        code = event.input['code']
        # Vex scans for: exec/eval, file ops, network, secrets
        verdict = vex.verify({
            'code_safety': code,
            'syntax_validity': True,
            'no_secrets': True,
            'sandboxed': True
        })
        if not verdict.approved:
            raise ValueError(f'Blocked: {verdict.issues}')

# Register with BeeAI
agent.add_event_listener('tool_start', verify_code_safety)
agent.add_event_listener('tool_end', verify_code_safety)
agent.add_event_listener('memory_update', verify_code_safety)

@vex.policy('dependency-safety')
def verify_dependencies(event):
    if 'import' in event.input.get('code', ''):
        imports = extract_imports(event.input['code'])
        allowed = {'numpy', 'pandas', 'pytest'}
        risky = [imp for imp in imports if imp not in allowed]

        verdict = vex.verify({
            'dependencies': risky,
            'allowlist': list(allowed),
            'network_access': False
        })
        return verdict.approved
    return True

def extract_imports(code):
    tree = ast.parse(code)
    return {node.names[0].name for node in ast.walk(tree) 
            if isinstance(node, ast.ImportFrom) or isinstance(node, ast.Import)}
